// // This module implements a 2-to-1 multiplexer with dual selection inputs. The output is assigned the value of input b when both selection lines are low (00) or when sel_b1 is high while sel_b2 is low (01). The output takes the value of input a when sel_b2 is high (10 or 11).
module top_module(
    input a,
    input b,
    input sel_b1,
    input sel_b2,
    output reg out_always
);always @(*) begin
        case ({sel_b2, sel_b1})
            2'b00: out_always = a;
            2'b01: out_always = a;
            2'b10: out_always = b;
            2'b11: out_always = b;
        endcase
    end

endmodule
